final:
module RefModule (  
    input J,  
    input K,  
    input clk,  
    output reg Q  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        if (J && K)  
            Q <= ~Q;  
        else if (J)  
            Q <= 1;  
        else if (K)  
            Q <= 0;  
    end  
endmodule
